var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"이거 대단하네~","JPN":"すごいわね～","ENG":"Impressive.","TWN":"真厲害呢～"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"이런 류의 도박에는 나도 제법 소질이 있다고 생각했는데…….","JPN":"この類の賭け事には結構才能がある方だって自負してたけど……","ENG":"I thought I had a decent knack for this kind of gamble myself...","TWN":"我本來也自認對這種賭局挺有天分的……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"설마 이렇게까지 배팅을 키울 수 있다니, 나는 어디 가서 명함도 못 내밀겠어~","JPN":"まさかここまで掛け金を膨らませることができるなんて。私もまだまだね～","ENG":"To think someone could raise the stakes this far, I wouldn't even dare hand out my card anymore.","TWN":"沒想到能把賭注抬高到這種程度，看來我在外面不好意思遞名片了呢～"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"베네딕트가 교단으로부터 어떤 지원을 받고 있다는 건 알고 있었어.","JPN":"ベネディクトが教団から何らかの支援を受けていることは知っていたわ。","ENG":"I knew Benedict was receiving some kind of support from the faction.","TWN":"我早就知道本尼迪克特得到教團的支援。"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"그렇기에 그를 도왔지. 암묵적으로 샤레이드는 학회의 영역이니까 말이야.","JPN":"だから彼を手伝ったの。暗黙的にシャレードは学会の領域だから。","ENG":"That's why I helped him. Implicitly, Charade is the Society's estate","TWN":"畢竟查雷德本就是學會的勢力範圍，所以我才暗中幫他一把。"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"베네딕트가 성공하든 실패하든, 학회와 교단은 이 문제로 마찰을 일으키겠지.","JPN":"ベネディクトが成功しても失敗しても、学会と教団はこの件でぶつかることになるという算段だった。","ENG":"Whether Benedict succeeded or failed, the Society and the faction were bound to clash over this.","TWN":"無論他成功或失敗，學會與教團都必定會因此產生摩擦。"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"한편으로는 그 정도가 한계였어.","JPN":"一方で、その程度が限界だったわ。","ENG":"At the same time, that was as far as things could go.","TWN":"而那也正是極限。"},"stage":{"bg":"HALL","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"영지 내에서 소란을 일으킨 변절자를 처단하는 것. 이건 법학부의 관할일 뿐이야.","JPN":"領地内で騒ぎを立てた変節者を処断すること。それは単に法学部の管轄に過ぎないもの。","ENG":"Dealing with a turncoat who caused trouble within the territory was strictly the Law Department's jurisdiction.","TWN":"清除在領地內作亂的叛徒，本來就只是法學院的職權而已。"},"stage":{"bg":"HALL","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"지금의 레지나는 그런 사소한 일 같은 건 안중에도 없었을 테니까.","JPN":"今のレジーナはそんな些細なことなんて眼中にもないはずだし。","ENG":"The current Regina wouldn't have paid any mind to something that trivial.","TWN":"現在的蕾佳娜根本不會在意這種小事。"},"stage":{"bg":"HALL","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"하지만 그 아이가 이 판에 뛰어들면서 모든 게 역전됐지.","JPN":"だけど、あの子が現れてすべてがひっくり返った。","ENG":"But once that child stepped into the game, everything turned upside down.","TWN":"但那孩子介入後顛覆了一切。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"쓸모없는 그릇 하나가 끼어들면서, 베네딕트는 새로운 그릇을 쓸 수밖에 없었고.","JPN":"想定外の器が割り込んできたおかげで、ベネディクトはその新しい器を使うしかなくなり……","ENG":"With one useless vessel getting involved, Benedict had no choice but to use a new vessel.","TWN":"一個沒用的器皿插手，逼得本尼迪克特不得不啟用新器皿。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"나아가 프리드웬까지 이 사태에 발을 뺄 수 없게 만들어 버렸지.","JPN":"ひいてはプリドウェンまでこの事態に巻き込んだ。","ENG":"And that dragged even Prydwen into a situation they could no longer stay out of.","TWN":"甚至讓普利多溫也無法從這起事件抽身。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"그리고 그 결과…….","JPN":"その結果……","ENG":"And as a result...","TWN":"而那結果便是……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"샤레이드를 지키려는 모든 이들의 노력은 결국 파국으로 치닫았고.","JPN":"シャレードを守ろうとするすべての人たちの努力は破局へと繋がり……","ENG":"All the efforts of those who tried to protect Charade ultimately spiraled into catastrophe.","TWN":"所有試圖守護查雷德的人，最終都走向毀滅。"},"stage":{"bg":"OMEN_CHARADE_01","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"무너져 내리는 도시 속에서, 학회와 교단은 서로의 존재를 걸고 싸우고 있지.","JPN":"崩れ落ちる都市を舞台に、学会と教団は互いの存在をかけて戦っている。","ENG":"Within the collapsing city, the Society and the faction are fighting, staking their very existence.","TWN":"在崩塌的城市中，學會與教團正賭上彼此的存在而戰。"},"stage":{"bg":"OMEN_CHARADE_01","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"정말로 파멸적인 재능이네, 각본가 양.","JPN":"本当、破滅的な才能だわ。脚本家のお嬢さん。","ENG":"Truly a ruinous talent, Ms. Playwright.","TWN":"真是毀滅性的才能呢，編劇小姐。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"이 모든 시추에이션이 단 한 장의 <color=#ffd34c>초대장</color>으로부터 시작되었다고 하면, 그걸 누가 믿어 주기나 할까?","JPN":"このすべてのシチュエーションがたった1枚の<color=#ffd34c>招待状</color>から始まったと言ったら、誰が信じるかしら。","ENG":"If someone said all of this started from a single <color=#ffd34c>invitation</color>, who would ever believe it?","TWN":"要說這一切，都是從一張<color=#ffd34c>邀請函</color>開始的，又有誰會相信呢？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"UMBRELLA_CHARADE_NULL_NULL","text":{"KOREA":"그야, 진심을 담은 편지에는 그만한 힘이 있으니까요.","JPN":"真心を込めた手紙にはそれだけの力がありますからね。","ENG":"That's because a heartfelt letter carries that much power.","TWN":"那是因為真心寫下的信，確實擁有那樣的力量啊。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UMBRELLA_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"UMBRELLA_CHARADE_NULL_NULL","text":{"KOREA":"제가 각본을 쓰기 시작한 것도, 한 장의 <color=#ffd34c>팬레터</color> 때문이었거든요.","JPN":"私が脚本を書き始めたのも、1枚の<color=#ffd34c>ファンレター</color>がきっかけだったんです。","ENG":"After all, the reason I started writing scripts was because of a single <color=#ffd34c>fan letter</color>.","TWN":"我開始寫劇本，也是因為一封<color=#ffd34c>粉絲信</color>呢。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UMBRELLA_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"팬레터라…….","JPN":"ファンレターね……","ENG":"A fan letter...","TWN":"粉絲信啊……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"UMBRELLA_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"후훗, 이거 점점 각본가 양이 마음에 드는데?","JPN":"ふふっ、ますます脚本家のお嬢さんが好きになってきちゃったわ。","ENG":"Heh, I'm starting to like you more and more, scriptwriter.","TWN":"呵呵，我是越來越喜歡你了，編劇小姐。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"UMBRELLA_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"그래서 우리 아가씨는 대체 누굴까?","JPN":"それで、あなたはいったい何者なの？","ENG":"So then, who exactly are you?","TWN":"所以，我們小姐究竟是誰呢？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"내가 알기로는 이런 각본을 짤 수 있는 사람은 이 세계에 한 사람밖에 없거든?","JPN":"私の知る限り、こんな脚本を書ける人は世界に1人しかいないのよね。","ENG":"As far as I know, there's only one person in this world capable of writing a script like this.","TWN":"就我所知，這世界只有一位能寫出這種劇本的人。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"신비주의 여배우, 천재 각본가, 국제적 테러리스트, 관리국 비밀 요원 그리고…….","JPN":"謎の多い女優、天才脚本家、国際的テロリスト、管理局のエージェント、そして……","ENG":"A mysterious actress, a genius scriptwriter, an international terrorist, a secret Administration agent, and...","TWN":"神祕主義女演員、天才編劇、國際恐怖分子、管理局祕密特工，以及……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"마왕 타기리온의 사도, 스완 클레어.","JPN":"魔王タギリオンの使徒、スワン・クレア。","ENG":"The Demon Lord Thagirion's Apostle, Swan Claire.","TWN":"魔王塔基里翁的使徒，史旺．克萊爾。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"UMBRELLA_CHARADE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UMBRELLA_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"스완은 거울을 통해, 얼마든지 모습을 바꿀 수 있다고 하잖아?","JPN":"スワンは鏡を使っていくらでも姿を変えられるらしいじゃない？","ENG":"They say Swan can change her appearance freely through mirrors, don't they?","TWN":"不是說史旺能透過鏡子任意改變外貌嗎？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"지금 그 모습도 네 가면 중 하나일까, 스완?","JPN":"今のその姿もあなたの仮面の一つなのかしら？　スワン。","ENG":"Is the form you're wearing now just another one of your masks, Swan?","TWN":"現在這副模樣也是你其中一張面具嗎，史旺？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"UMBRELLA_CHARADE_NULL_NULL","text":{"KOREA":"스완이라…….","JPN":"スワン……","ENG":"Swan...","TWN":"史旺這個名字……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"UMBRELLA_CHARADE_NULL_NULL","text":{"KOREA":"그 이름은 한때 제 각오였답니다.","JPN":"その名はかつての私の覚悟でした。","ENG":"That name was once my resolve.","TWN":"是我下定決心時的名字。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"UMBRELLA_CHARADE_NULL_NULL","text":{"KOREA":"과거로부터 도망치며, 새로운 무대에 서기 위한 각오였죠.","JPN":"過去から逃げ、新しい舞台に立つための覚悟。","ENG":"A resolve to flee from the past and step onto a new stage.","TWN":"那是為了逃離過去，站上新舞台的決心。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"UMBRELLA_CHARADE_NULL_NULL","text":{"KOREA":"그때도, 그리고 지금도 저는 알고 있어요.","JPN":"あの頃も、そして今も私は知っています。","ENG":"Even back then, and even now, I know this much.","TWN":"無論是那時還是現在，我都很清楚。"},"stage":{"bg":"SWANSONG_04","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"UMBRELLA_CHARADE_NULL_NULL","text":{"KOREA":"도망치는 것만으로는 그 무엇도 바꿀 수 없다는 것쯤은…….","JPN":"逃げるだけでは何も変えられないということくらい……","ENG":"That running away alone can never change anything...","TWN":"一味逃跑，什麼也改變不了……"},"stage":{"bg":"SWANSONG_04","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"UMBRELLA_CHARADE_NULL_NULL","text":{"KOREA":"저는 백조가 되길 바랐을 뿐이지, 백조였던 적은 단 한 번도 없어요.","JPN":"私は白鳥になることに憧れただけで、一度も白鳥であったことはありませんでした。","ENG":"I only ever wanted to be a swan, but never was I to become one.","TWN":"我只是嚮往成為白天鵝，卻從來不曾是白天鵝。"},"stage":{"bg":"SWANSONG_01","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"UMBRELLA_CHARADE_NULL_NULL","text":{"KOREA":"무력했던 무명 시절을 후회하며, 우아한 백조를 동경했던 걸지도 모르죠.","JPN":"無力だった無名時代を悔い、優雅な白鳥に憧れていたのかもしれません。","ENG":"Perhaps I envied the graceful swan, regretting my powerless days of obscurity.","TWN":"或許我是在後悔無力的無名時代，嚮往優雅的白天鵝吧。"},"stage":{"bg":"SWANSONG_01","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"UMBRELLA_CHARADE_NULL_NULL","text":{"KOREA":"하지만 지금은 더 이상 나 자신으로부터 도망치지 않아요.","JPN":"ですが、今はもう私自身から逃げたりしません。","ENG":"But now, I no longer run from myself.","TWN":"但現在，我已不再逃避自己。"},"stage":{"bg":"SWANSONG_01","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"그러니까 저는 아이린 애들러…….","JPN":"私は、アイリーン・アドラー……","ENG":"That's why I am Irene Adler...","TWN":"所以，我是愛琳．艾德勒……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"그 이름이 제가 새로운 무대에서 스스로에게 부여한 배역의 이름입니다.","JPN":"この名が、新たな舞台で私が自分に与えた役の名前です。","ENG":"The name of the role I chose for myself on this new stage.","TWN":"那是我在新舞台上賦予自己的角色名字。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};